  cd: "CD", cpm: "CPM", ctr: "CTR", dti: "DTI", egfr: "eGFR", fha: "FHA",
  gcf: "GCF", gcd: "GCD", gdp: "GDP", gfr: "GFR", gpa: "GPA", heloc: "HELOC",
  hp: "HP", ira: "IRA", irr: "IRR", lcm: "LCM", mpg: "MPG", pmi: "PMI",
  pv: "PV", rmd: "RMD", roi: "ROI", sip: "SIP", tdee: "TDEE", tvm: "TVM",
