function buildFaqs(path: string, label: string, profile: TopicProfile) {
  const subject = shortName(label).toLowerCase();
  const specific = [
    {
      q: `How does the ${label} calculate ${subject}?`,
      a: profile.method,
    },
    {
      q: `What is a realistic example for the ${label}?`,
      a: profile.example,
    },
    {
      q: `When should I use this ${label}?`,
      a: `Use it for ${sentenceList(profile.useCases)}. It is most helpful when you want a quick answer plus enough context to compare choices.`,
    },
    {
      q: `How can I make the ${label} more accurate?`,
      a: `Start with ${sentenceList(profile.tips)}. If the result affects health, taxes, lending, legal obligations, or safety, confirm the final decision with a qualified source.`,
    },
    {
      q: `What related terms should I understand for ${subject}?`,
      a: `Useful related terms include ${sentenceList(profile.keywords)}. Knowing these makes it easier to interpret the result instead of only copying the final number.`,
    },
  ];

  if (has(path, "bmi", "overweight", "anorexic")) {
    specific[4] = {
      q: "Is BMI enough to judge health?",
      a: "No. BMI is a screening metric, not a diagnosis. Body composition, age, pregnancy, medical history, and clinician guidance can all change how the number should be understood.",
    };
  }
  if (has(path, "mortgage", "loan", "credit-card", "debt")) {
    specific[4] = {
      q: "Should I focus on monthly payment or total interest?",
      a: "Review both. Monthly payment affects cash flow, while total interest shows the long-term cost of borrowing. A lower payment can still cost more over time.",
    };
  }
  if (has(path, "investment", "roi", "irr", "retirement", "401k", "ira")) {
    specific[4] = {
      q: "Are investment results guaranteed?",
      a: "No. Investment calculators use assumptions. Returns, taxes, inflation, fees, and timing can change real outcomes, so compare conservative and optimistic cases.",
    };
  }

  return specific;
}

function buildParagraphs(label: string, profile: TopicProfile) {
  const primary = `free ${label.toLowerCase()} online`;
  const isConstruction = profile.keywords.some((keyword) =>
    /insulation|material|construction|coverage|waste|takeoff|spray foam|fiberglass|crawl space|wall/.test(keyword)
  );
  const searchContext =
    profile.keywords.length >= 5
      ? `Those details are why people search for ${profile.keywords[0]}, ${profile.keywords[1]}, or ${profile.keywords[2]}: they are usually trying to price a real job, choose a material, or check whether a supplier quantity makes sense before buying. The same estimate can also help when a project starts as a ${profile.keywords[3]} search and then turns into a more specific ${profile.keywords[4]} question.`
      : `Those related checks, including ${sentenceList(profile.keywords)}, are useful when the first answer raises a follow-up question.`;
  const decisionContext = isConstruction
    ? "These examples matter because most construction calculator searches come from a real job: measuring a surface, comparing material types, adding waste, checking a supplier quantity, or deciding whether the project budget still makes sense."
    : "These examples matter because most calculator searches come from a real decision: checking a payment, understanding a health range, measuring a project, reviewing a dataset, or comparing two options before spending time or money.";
  return [
    `The ${label} helps ${profile.audience} ${profile.action} without building a spreadsheet from scratch. Instead of giving a bare number, the page is designed to make the result useful: the inputs stay visible, the output is readable, and supporting details help you understand what changed. This ${primary} is practical for quick checks and deeper comparisons because it works on mobile and desktop, gives instant results, and keeps the calculation focused on the task at hand.`,
    `${profile.method} That makes the ${label} useful for learning as well as planning. You can adjust a single assumption, compare the new result with the previous one, and see which input has the biggest effect. ${searchContext}`,
    `${profile.example} Common use cases include ${sentenceList(profile.useCases)}. ${decisionContext} The goal is to give a clear next step, not just a number that disappears without context.`,
    `For better results, ${sentenceList(profile.tips)}. Also watch for common entry mistakes such as mixing monthly and yearly values, entering percentages as whole numbers in the wrong place, using rounded measurements too early, or copying a value into the wrong field. The ${label} is strongest when the inputs match your real situation and when you compare the answer with the table and examples on the page.`,
    `This ${primary} is 100% free, no signup required, and free for everyone who needs a fast browser-based answer. Bookmark it if you repeat the calculation often, share it when someone needs the same estimate, and use the related calculators when the decision has more than one part. CalcHive keeps these pages readable and practical so each calculator can stand on its own as a helpful reference, not just another duplicate tool page.`,
  ];
}

export default function CalculatorSeoContent() {
  const [location] = useLocation();
  const path = location.split("?")[0];
  const route = routeMap.get(path);
  if (!route) return null;

  const label = labelFromPath(path);
  const profile = specialize(path, label, route.category);
  const paragraphs = buildParagraphs(label, profile);
  const breadcrumbSchema = {
    "@context": "https://schema.org",
    "@type": "BreadcrumbList",
    "itemListElement": [
      { "@type": "ListItem", "position": 1, "name": "Home", "item": `${SITE_URL}/` },
      { "@type": "ListItem", "position": 2, "name": route.category, "item": `${SITE_URL}/?cat=${encodeURIComponent(route.category).replace(/%20/g, "+")}` },
      { "@type": "ListItem", "position": 3, "name": label, "item": `${SITE_URL}${path}` },
    ],
  };

  return (
    <section className="max-w-3xl mx-auto px-4 sm:px-6 pb-10" aria-label={`${label} reference and guide`}>
      <Helmet>
        <script type="application/ld+json">{JSON.stringify(breadcrumbSchema)}</script>
      </Helmet>
      <style>{`
        .calchive-seo-table-wrap{overflow-x:auto;margin-bottom:2rem}
        .calchive-seo-table{width:100%;border-collapse:separate;border-spacing:0;border:1px solid hsl(var(--border));border-radius:.75rem;overflow:hidden;font-size:.875rem}
        .calchive-seo-table th{background:hsl(var(--muted)/.6);font-weight:700;color:hsl(var(--foreground));text-align:left;padding:.75rem}
        .calchive-seo-table td{padding:.7rem .75rem;border-top:1px solid hsl(var(--border));color:hsl(var(--muted-foreground));vertical-align:top}
        .calchive-seo-table tbody tr:nth-child(even){background:hsl(var(--muted)/.24)}
        .calchive-seo-table .positive{color:rgb(22 163 74);font-weight:700}
        .calchive-seo-table .negative{color:rgb(220 38 38);font-weight:700}
      `}</style>
      <h2 className="text-2xl font-bold text-foreground mb-4">{label} Practical Reference</h2>
      <div className="calchive-seo-table-wrap">
        <table className="calchive-seo-table">
          <thead>
            <tr>{["Reference Point", "Value or Range", "Why It Matters", "Practical Note"].map((heading) => <th key={heading}>{heading}</th>)}</tr>
          </thead>
          <tbody>
            {profile.rows.map((row) => (
              <tr key={row[0]}>
                <td className="font-semibold text-foreground">{row[0]}</td>
                <td className={row[4] ?? ""}>{row[1]}</td>
                <td>{row[2]}</td>
                <td>{row[3]}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {route.category === "Financial" ? (
        <FinancialExpandedContent path={path} label={label} />
      ) : route.category === "Health" ? (
        <HealthExpandedContent path={path} label={label} />
        ) : route.category === "Math" ? (
          <MathExpandedContent path={path} label={label} />
        ) : route.category === "Tools" ? (
          <ToolsExpandedContent path={path} label={label} />
        ) : route.category === "Date & Time" ? (
          <DateTimeExpandedContent path={path} label={label} />
      ) : route.category === "Housing" ? (
        <HousingExpandedContent path={path} label={label} />
      ) : route.category === "Measurement" ? (
        <MeasurementExpandedContent path={path} label={label} />
      ) : route.category === "Electronics" ? (
        <ElectronicsExpandedContent path={path} label={label} />
      ) : route.category === "Internet" ? (
        <InternetExpandedContent path={path} label={label} />
      ) : route.category === "Everyday" ? (
        <EverydayExpandedContent path={path} label={label} />
      ) : route.category === "Weather" ? (
        <WeatherExpandedContent path={path} label={label} />
      ) : route.category === "Transportation" ? (
        <TransportationExpandedContent path={path} label={label} />
      ) : route.category === "Entertainment" ? (
        <EntertainmentExpandedContent path={path} label={label} />
      ) : (
          <section className="mb-8">
          <h2 className="text-2xl font-bold text-foreground mb-4">{label} Practical Guide and Examples</h2>
          <div className="space-y-4 text-muted-foreground leading-relaxed">
            {paragraphs.map((paragraph) => <p key={paragraph}>{paragraph}</p>)}
          </div>
        </section>
      )}
    </section>
  );
}
